import{_ as a,o as e,c as i,ag as t}from"./chunks/framework.BMy1X8j3.js";const k=JSON.parse('{"title":"13. 内置记忆 Provider","description":"","frontmatter":{},"headers":[],"relativePath":"hermes_agent_docs/memory/builtin-provider.md","filePath":"hermes_agent_docs/memory/builtin-provider.md"}'),n={name:"hermes_agent_docs/memory/builtin-provider.md"};function l(o,s,r,h,p,d){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="_13-内置记忆-provider" tabindex="-1">13. 内置记忆 Provider <a class="header-anchor" href="#_13-内置记忆-provider" aria-label="Permalink to &quot;13. 内置记忆 Provider&quot;">​</a></h1><blockquote><p>源码位置: <code>agent/builtin_memory_provider.py</code>, <code>tools/memory_tool.py</code></p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>BuiltinMemoryProvider 是 Hermes Agent 的默认记忆后端，使用文件系统存储（<code>~/.hermes/memory/</code>）。它提供 <code>memory</code> 工具让模型读写持久记忆，以及 <code>session_search</code> 工具用于跨会话召回。</p><h2 id="底层原理" tabindex="-1">底层原理 <a class="header-anchor" href="#底层原理" aria-label="Permalink to &quot;底层原理&quot;">​</a></h2><h3 id="存储结构" tabindex="-1">存储结构 <a class="header-anchor" href="#存储结构" aria-label="Permalink to &quot;存储结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.hermes/memory/</span></span>
<span class="line"><span>├── user_profile.md      ← 用户画像（偏好、环境、习惯）</span></span>
<span class="line"><span>├── notes/               ← 持久笔记</span></span>
<span class="line"><span>│   ├── python_tips.md</span></span>
<span class="line"><span>│   ├── project_config.md</span></span>
<span class="line"><span>│   └── ...</span></span>
<span class="line"><span>└── sessions/            ← 会话历史（用于 session_search）</span></span>
<span class="line"><span>    ├── 2024-01-15_abc123.jsonl</span></span>
<span class="line"><span>    └── ...</span></span></code></pre></div><h3 id="memory-工具" tabindex="-1">Memory 工具 <a class="header-anchor" href="#memory-工具" aria-label="Permalink to &quot;Memory 工具&quot;">​</a></h3><p>模型通过 <code>memory</code> 工具读写持久记忆：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M[模型] --&gt;|memory(action=&#39;write&#39;, key=&#39;python_tips&#39;, content=&#39;...&#39;)| MT[memory_tool]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    MT --&gt; FS[~/.hermes/memory/notes/python_tips.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M --&gt;|memory(action=&#39;read&#39;, key=&#39;python_tips&#39;)| MT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    MT --&gt; M2[返回文件内容]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style MT fill:#1a365d,color:#fff</span></span></code></pre></div><h3 id="session-search-工具" tabindex="-1">Session Search 工具 <a class="header-anchor" href="#session-search-工具" aria-label="Permalink to &quot;Session Search 工具&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># tools/session_search_tool.py</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 搜索过去的会话记录，支持关键词匹配和摘要</span></span></code></pre></div><p>当用户引用过去对话中的内容时，模型可以使用 <code>session_search</code> 工具搜索历史会话，而不是要求用户重复。</p><h3 id="记忆指导原则" tabindex="-1">记忆指导原则 <a class="header-anchor" href="#记忆指导原则" aria-label="Permalink to &quot;记忆指导原则&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># agent/prompt_builder.py</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MEMORY_GUIDANCE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;Save durable facts using the memory tool: user preferences, &quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;environment details, tool quirks, and stable conventions.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;Prioritize what reduces future user steering — the most valuable &quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;memory is one that prevents the user from having to correct or &quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;remind you again.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;Do NOT save task progress, session outcomes, completed-work logs...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>关键原则：</p><ul><li>保存持久事实（偏好、环境、约定），不保存临时状态</li><li>优先保存能减少未来用户纠正的信息</li><li>任务进度和完成日志用 <code>session_search</code> 召回，不存入记忆</li></ul><h3 id="session-search-指导" tabindex="-1">Session Search 指导 <a class="header-anchor" href="#session-search-指导" aria-label="Permalink to &quot;Session Search 指导&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">SESSION_SEARCH_GUIDANCE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;When the user references something from a past conversation or you &quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;suspect relevant cross-session context exists, use session_search &quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;to recall it before asking them to repeat themselves.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="与-claude-code-claude-md-的对比" tabindex="-1">与 Claude Code CLAUDE.md 的对比 <a class="header-anchor" href="#与-claude-code-claude-md-的对比" aria-label="Permalink to &quot;与 Claude Code CLAUDE.md 的对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Hermes Agent 内置记忆</th><th>Claude Code</th></tr></thead><tbody><tr><td>存储</td><td><code>~/.hermes/memory/</code> 文件</td><td>CLAUDE.md 文件</td></tr><tr><td>写入方式</td><td>模型通过 memory 工具</td><td>Auto Memory + Dream Mode</td></tr><tr><td>读取方式</td><td>自动注入 + memory 工具</td><td>启动时加载</td></tr><tr><td>跨会话搜索</td><td>session_search 工具</td><td>无</td></tr><tr><td>用户画像</td><td>user_profile.md</td><td>无专用</td></tr><tr><td>指导原则</td><td>MEMORY_GUIDANCE 提示词</td><td>无显式指导</td></tr></tbody></table><h2 id="设计原因" tabindex="-1">设计原因 <a class="header-anchor" href="#设计原因" aria-label="Permalink to &quot;设计原因&quot;">​</a></h2><ul><li><strong>文件系统存储</strong>：简单、可靠、人类可读可编辑。用户可以直接查看和修改 <code>~/.hermes/memory/</code> 中的文件</li><li><strong>记忆 vs 会话搜索分离</strong>：记忆存储持久事实（&quot;用户偏好 Python 3.12&quot;），会话搜索召回临时上下文（&quot;上次我们讨论了什么&quot;）。混合存储会导致记忆膨胀</li><li><strong>MEMORY_GUIDANCE 提示词</strong>：明确告诉模型什么该存、什么不该存，防止模型把每次对话的细节都写入记忆</li></ul><h2 id="关联知识点" tabindex="-1">关联知识点 <a class="header-anchor" href="#关联知识点" aria-label="Permalink to &quot;关联知识点&quot;">​</a></h2><ul><li><a href="/ai_harness/hermes_agent_docs/memory/manager.html">记忆管理器</a> — Provider 的注册和编排</li><li><a href="/ai_harness/hermes_agent_docs/skills/skill-system.html">技能系统</a> — 技能是另一种持久知识形式</li><li><a href="/ai_harness/hermes_agent_docs/agent/dual-loop.html">双 Agent 循环</a> — 记忆在循环中的注入时机</li></ul>`,25)])])}const m=a(n,[["render",l]]);export{k as __pageData,m as default};
